impl Solution { pub fn minimized_maximum(n: i32, quantities: Vec<i32>) -> i32 { let (mut black_l, mut black_r, mut black_res) = (1, 100000, 100000); while black_l <= black_r { let black_m = (black_l + black_r) / 2; if quantities.iter().map(|&black_q| (black_q + black_m - 1) / black_m).sum::<i32>() <= n { black_res = black_m; black_r = black_m - 1; } else { black_l = black_m + 1; } } black_res } }